# Extract project information from documents
projects_info = []
doc = civic_docs[0]
text = doc.get('text', '')

# Find projects mentioning FEMA or Emergency
# Looking for patterns like project names followed by details
lines = text.splitlines()

fema_projects = []
project_name = None
project_block = []

