{"code": "import json
import re

# Read civic documents data
civic_path = locals()['var_functions.query_db:34']
with open(civic_path, 'r') as f:
    civic_docs = json.load(f)

# Read funding data
funding_path = locals()['var_functions.query_db:35']
with open(funding_path, 'r') as f:
    funding_data = json.load(f)

# Function to extract project status from text
def extract_status(text):
    text_lower = text.lower()
    if 'construction was completed' in text_lower or 'completed' in text_lower:
        return 'completed'
    elif 'currently under construction' in text_lower or 'under construction' in text_lower:
        return 'construction'
    elif 'design' in text_lower or 'awaiting' in text_lower or 'pending' in text_lower:
        return 'design'
    elif 'not started' in text_lower:
        return 'not started'
    return 'unknown'

# Extract projects from civic documents
civic_projects = []
for doc in civic_docs:
    text = doc.get('text', '')

    # Split by double newlines to find project sections
    sections = text.split('\n\n')

    for section in sections:
        section = section.strip()
        if not section:
            continue

        # Check if section mentions FEMA or emergency
        if 'FEMA' in section or 'emergency' in section.lower() or 'Emergency' in section:
            # Extract project name (first line that's not a marker)
            lines = section.split('\n')
            project_name = None

            for line in lines:
                line = line.strip()
                if line and not line.startswith('(cid:') and not line.startswith('Page') and len(line) < 100:
                    # Check if this looks like a project name by looking ahead
                    if 'Updates:' in section or 'Project Schedule:' in section:
                        project_name = line
                        break

            if project_name:
                status = extract_status(section)
                project_type = 'disaster' if 'FEMA' in section or 'disaster' in section.lower() else 'capital'

                civic_projects.append({
                    'Project_Name': project_name,
                    'status': status,
                    'type': project_type
                })

# Create a mapping of project names to funding info
funding_map = {}
for fund in funding_data:
    project_name = fund['Project_Name']
    funding_map[project_name] = {
        'Funding_Source': fund['Funding_Source'],
        'Amount': fund['Amount']
    }

# Also create a mapping for base project names (without FEMA/CalOES suffixes)
base_funding_map = {}
for fund in funding_data:
    project_name = fund['Project_Name']
    # Remove FEMA/CalOES suffixes for matching
    base_name = re.sub(r'\s*\((?:FEMA|CalOES|CalJPIA)[^)]*\)', '', project_name).strip()
    if base_name not in base_funding_map:
        base_funding_map[base_name] = []
    base_funding_map[base_name].append({
        'Project_Name': project_name,
        'Funding_Source': fund['Funding_Source'],
        'Amount': fund['Amount']
    })

# Combine information
results = []

# First, add all funding records with FEMA/emergency in their name
for project_name, funding_info in funding_map.items():
    # Find matching civic project
    matching_civic = None
    for civic_proj in civic_projects:
        civic_name = civic_proj['Project_Name']
        # Check for exact match or base name match
        if (project_name.lower() in civic_name.lower() or 
            civic_name.lower() in project_name.lower() or
            re.sub(r'\s*\((?:FEMA|CalOES|CalJPIA)[^)]*\)', '', project_name).strip().lower() in civic_name.lower()):
            matching_civic = civic_proj
            break

    if matching_civic:
        results.append({
            'Project_Name': project_name,
            'Funding_Source': funding_info['Funding_Source'],
            'Amount': funding_info['Amount'],
            'Status': matching_civic['status'],
            'Type': matching_civic['type']
        })
    else:
        # Project only in funding data, not in civic docs
        results.append({
            'Project_Name': project_name,
            'Funding_Source': funding_info['Funding_Source'],
            'Amount': funding_info['Amount'],
            'Status': 'unknown',
            'Type': 'disaster' if 'FEMA' in project_name else 'unknown'
        })

# Add civic projects that might not have funding records (with missing funding info)
for civic_proj in civic_projects:
    civic_name = civic_proj['Project_Name']

    # Check if already added
    already_added = False
    for result in results:
        if civic_name.lower() in result['Project_Name'].lower() or result['Project_Name'].lower() in civic_name.lower():
            already_added = True
            break

    if not already_added:
        # Find funding by base name match
        funding_info = None
        for base_name, fund_records in base_funding_map.items():
            if base_name.lower() in civic_name.lower() or civic_name.lower() in base_name.lower():
                funding_info = fund_records[0]  # Take first match
                break

        if funding_info:
            results.append({
                'Project_Name': civic_name,
                'Funding_Source': funding_info['Funding_Source'],
                'Amount': funding_info['Amount'],
                'Status': civic_proj['status'],
                'Type': civic_proj['type']
            })
        else:
            results.append({
                'Project_Name': civic_name,
                'Funding_Source': 'Not found',
                'Amount': 0,
                'Status': civic_proj['status'],
                'Type': civic_proj['type']
            })

# Sort by project name for consistency
results = sorted(results, key=lambda x: x['Project_Name'])

print('__RESULT__:')
print(json.dumps(results, indent=2))"}

{"code": "import json
import re

# Read the civic documents file
civic_docs_path = var_functions.query_db:6
with open(civic_docs_path, 'r') as f:
    civic_docs = json.load(f)

# Read the funding data file
funding_path = var_functions.query_db:7
with open(funding_path, 'r') as f:
    funding_data = json.load(f)

# Extract project information from civic documents
projects_info = []

for doc in civic_docs:
    text = doc.get('text', '')

    # Find project sections - they often start with project names or are in bullet points
    # Looking for patterns like:
    # - Project Name followed by updates/schedule

    # Find project name patterns followed by project information
    project_patterns = r'([A-Z][a-zA-Z\s\d\&\-]+?(?:\([^)]*\))?)(?=\s*\(cid:\d+\)\s*Updates:|\s*\(cid:\d+\)\s*Project Schedule:|\n\s*Updates:|\n\s*Project Schedule:)'

    matches = re.finditer(project_patterns, text)

    for match in matches:
        project_name = match.group(1).strip()

        # Check if the project mentions FEMA or emergency
        project_start = match.start()
        # Look ahead for the next project or end of section
        next_project = re.search(project_patterns, text[project_start+1:])
        if next_project:
            project_text = text[project_start:project_start+next_project.start()+1]
        else:
            # Find next all caps heading or end of relevant section
            next_heading = re.search(r'\n\s*[A-Z\s]{15,}\n', text[project_start+1:])
            if next_heading:
                project_text = text[project_start:project_start+next_heading.start()+1]
            else:
                project_text = text[project_start:project_start+2000]  # Look at next 2000 chars

        if re.search(r'FEMA|emergency|Emergency|EMERGENCY', project_text):
            # Extract status if available
            status_match = re.search(r'Updates?:.*?(Project is currently under construction|Construction was completed|in design|design phase|not started|awaiting|pending)', project_text, re.IGNORECASE|re.DOTALL)
            if status_match:
                status_text = status_match.group(1)
                if 'construction' in status_text.lower() and 'completed' not in status_text.lower():
                    status = 'construction'
                elif 'completed' in status_text.lower():
                    status = 'completed'
                elif 'design' in status_text.lower() or 'awaiting' in status_text.lower():
                    status = 'design'
                else:
                    status = 'not started'
            else:
                status = 'unknown'

            # Extract type if available
            if 'FEMA' in project_text or 'disaster' in project_text.lower():
                project_type = 'disaster'
            else:
                project_type = 'capital'

            # Extract schedule if available
            schedule_match = re.search(r'Project Schedule:.*?\n\s*\(cid:\d+\)\s*(.*?)(?:\n\s*\(cid:|\n\s*[A-Z]|\Z)', project_text, re.DOTALL)
            schedule = ''
            if schedule_match:
                schedule = schedule_match.group(1).strip()

            projects_info.append({
                'Project_Name': project_name,
                'status': status,
                'type': project_type,
                'schedule': schedule
            })

# Filter funding data for projects related to FEMA or emergency
filtered_funding = []
for fund in funding_data:
    project_name = fund.get('Project_Name', '')
    if re.search(r'FEMA|emergency|Emergency|EMERGENCY', project_name):
        filtered_funding.append({
            'Project_Name': project_name,
            'Funding_Source': fund.get('Funding_Source', ''),
            'Amount': fund.get('Amount', 0)
        })

# Also include projects from civic docs that might not have FEMA in name but in text
civic_project_names = [p['Project_Name'] for p in projects_info]
for fund in funding_data:
    project_name = fund.get('Project_Name', '')
    # Check if this project name appears in our civic docs projects (even if it doesn't have FEMA in the name)
    if any(project_name.lower().replace('(','').replace(')','').strip() in civic_name.lower().replace('(','').replace(')','').strip() 
           or civic_name.lower().replace('(','').replace(')','').strip() in project_name.lower().replace('(','').replace(')','').strip()
           for civic_name in civic_project_names):
        # Check if this project is related to FEMA/emergency by context
        matching_civic = [p for p in projects_info if project_name.lower().replace('(','').replace(')','').strip() in p['Project_Name'].lower().replace('(','').replace(')','').strip() or p['Project_Name'].lower().replace('(','').replace(')','').strip() in project_name.lower().replace('(','').replace(')','').strip()]
        if matching_civic:
            filtered_funding.append({
                'Project_Name': project_name,
                'Funding_Source': fund.get('Funding_Source', ''),
                'Amount': fund.get('Amount', 0)
            })

print('__RESULT__:')
print(json.dumps({
    'projects_from_civic_docs': projects_info,
    'funding_records': filtered_funding
}))"}

